        const ty = sy + ts * (0.3 + noise2d(col, row + i, 21) * 0.4);
        const treeR = ts * (0.08 + noise2d(col + i, row + i, 22) * 0.06);
        ctx.fillStyle = `rgba(0,0,0,0.08)`;
        ctx.beginPath();
        ctx.ellipse(tx + treeR * 0.3, ty + treeR * 1.2, treeR * 0.8, treeR * 0.3, 0, 0, Math.PI * 2);
