// src/hooks/useProfileWallet.ts
function useProfileWallet() {
  const { user } = useAuth();
  const { data: walletAddress, isLoading } = useQuery({
    queryKey: ["profile-wallet", user?.id],
    enabled: !!user?.id,
    staleTime: 30000,
    queryFn: async () => {
      const { data } = await supabase.from("profiles").select("wallet_address").eq("user_id", user.id).maybeSingle();
      return data?.wallet_address ?? null;
    }
  });
  return { walletAddress, isLoading };
}

